import React, { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import html2pdf from "html2pdf.js";
import "../styles/Certificado.css";

const CertificadoBancario = () => {
  const navigate = useNavigate();
  const certificadoRef = useRef();

  const [usuario, setUsuario] = useState({
    nombre: "",
    documento: "",
    cuenta: "",
    tipoCuenta: "Ahorros Digital",
    estado: "Activa",
    saldo: "$0 COP",
  });

  useEffect(() => {
    const documentoGuardado = localStorage.getItem("documento");

    if (!documentoGuardado) {
      navigate("/inicio");
      return;
    }

    const obtenerUsuario = async () => {
      try {
        const response = await fetch(
          `http://127.0.0.1:8000/usuario-documento/${documentoGuardado}`
        );

        if (!response.ok) {
          throw new Error("No se pudo obtener usuario");
        }

        const data = await response.json();

        setUsuario({
          nombre: data.nombre,
          documento: data.documento,
          cuenta: data.numero_cuenta || "9800456721",
          tipoCuenta: data.tipo_cuenta || "Ahorros Digital",
          estado: data.estado || "Activa",
          saldo: data.saldo
            ? `$${Number(data.saldo).toLocaleString("es-CO")} COP`
            : "$0 COP",
        });
      } catch (error) {
        console.error(error);
      }
    };

    obtenerUsuario();
  }, [navigate]);

  const descargarPDF = () => {
    html2pdf().from(certificadoRef.current).save(
      `Certificado_${usuario.documento}.pdf`
    );
  };

  const fechaActual = new Date().toLocaleDateString("es-CO", {
    day: "numeric",
    month: "long",
    year: "numeric",
  });

  return (
    <div className="certificado-page">
      <div className="certificado" ref={certificadoRef}>
        <div className="certificado-header">
          <img
            src="https://cdn-icons-png.flaticon.com/512/3135/3135715.png"
            alt="Logo"
            className="logo"
          />
          <h1>FINANCIERO S.A.S</h1>
          <h2>CERTIFICADO BANCARIO</h2>
        </div>

        <div className="certificado-body">
          <p>La presente certifica que el(la) señor(a):</p>

          <p className="dato">{usuario.nombre}</p>

          <p>Identificado(a) con Cédula de Ciudadanía No:</p>

          <p className="dato">{usuario.documento}</p>

          <p>
            Es titular de una cuenta en nuestra entidad financiera con los
            siguientes datos:
          </p>

          <ul>
            <li>
              <strong>Número de cuenta:</strong> {usuario.cuenta}
            </li>
            <li>
              <strong>Tipo de cuenta:</strong> {usuario.tipoCuenta}
            </li>
            <li>
              <strong>Estado:</strong> {usuario.estado}
            </li>
            <li>
              <strong>Saldo actual:</strong> {usuario.saldo}
            </li>
          </ul>

          <p>
            Este certificado se expide en Bogotá D.C. el día:
          </p>

          <p className="dato">{fechaActual}</p>
        </div>

        <div className="certificado-footer">
          <div className="firma-linea"></div>
          <p>Firma autorizada</p>
          <p>FINANCIERO S.A.S</p>
        </div>
      </div>

      <button className="descargar-btn" onClick={descargarPDF}>
        📥 Descargar Certificado PDF
      </button>
    </div>
  );
};

export default CertificadoBancario;
